    const long long INF = 1e18;

    // Precompute teleportList
    vector<vector<vector<pair<int, int>>>> teleportList(m, vector<vector<pair<int, int>>>(n));
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            for (int x = 0; x < m; ++x) {
