                    if (grid[x][y] <= grid[i][j]) {
                        teleportList[i][j].push_back({x, y});
                    }
                }
            }
        }
    }

    // Initialize distance array
    vector<vector<vector<long long>>> dist(m, vector<vector<long long>>(n, vector<long long>(k + 1, INF)));
    dist[0][0][0] = 0;

    // Priority queue: min-heap based on cost
    priority_queue<tuple<long long, int, int, long long>, vector<tuple<long long, int, int, long long>>, greater<>> pq;
    pq.push({0, 0, 0, 0});

    // Directions for regular moves: right and down
    vector<pair<int, int>> directions = {{0, 1}, {1, 0}};

    while (!pq.empty()) {
        auto [cost, i, j, t] = pq.top();
        pq.pop();

        // Check if destination
        if (i == m - 1 && j == n - 1) {
            return cost;
        }

        // Process regular moves
        for (auto [dx, dy] : directions) {
            int ni = i + dx;
            int nj = j + dy;
            if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                long long new_cost = cost + grid[ni][nj];
                if (new_cost < dist[ni][nj][t]) {
