#include <vector>
#include <queue>
#include <tuple>
#include <algorithm>
#include <climits>

using namespace std;

long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    int n = grid[0].size();

    // Precompute teleportList
    vector<vector<vector<pair<int, int>>>> teleportList(m, vector<vector<pair<int, int>>>(n));
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            for (int x = 0; x < m; ++x) {
                for (int y = 0; y < n; ++y) {
                    if (grid[x][y] <= grid[i][j]) {
                        teleportList[i][j].push_back({x, y});
                    }
                }
            }
        }
    }

    // Initialize distance array
    vector<vector<vector<long long>>> dist(m, vector<vector<long long>>(n, vector<long long>(k + 1, LLONG_MAX)));
    dist[0][0][0] = 0;

    // Priority queue: min-heap based on cost
    priority_queue<tuple<long long, int, int, int>> heap;
    heap.push({0, 0, 0, 0});

    // Directions for regular moves: right and down
    vector<pair<int, int>> directions = {{0, 1}, {1, 0}};

    while (!heap.empty()) {
        auto [stored_cost, i, j, t] = tie(get<0>(heap.top()), get<1>(heap.top()), get<2>(heap.top()), get<3>(heap.top()));
        heap.pop();
        long long actual_cost = -stored_cost;

        // Check if current cell is destination
        if (i == m - 1 && j == n - 1) {
            return actual_cost;
        }

        // Process regular moves
        for (const auto& [dx, dy] : directions) {
            int ni = i + dx;
            int nj = j + dy;
            if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                long long newCost = actual_cost + grid[ni][nj];
                if (newCost < dist[ni][nj][t]) {
                    dist[ni][nj][t] = newCost;
                    heap.push({-newCost, ni, nj, t});
                }
            }
        }

        // Process teleport moves
        if (t < k) {
            for (const auto& [x, y] : teleportList[i][j]) {
                long long new_t = t + 1;
                if (actual_cost < dist[x][y][new_t]) {
                    dist[x][y][new_t] = actual_cost;
                    heap.push({-actual_cost, x, y, new_t});
                }
            }
        }
    }

    // If not found (should not happen)
    return -1;
}
